import { invalidCells, userGrid } from './grid';
import { SUDOKU_SIZE } from '@sudoku/constants';
import { derived, writable } from 'svelte/store';

export const gamePaused = writable(true);

export const gameWon = derived(
	[userGrid, invalidCells],
	([$userGrid, $invalidCells]) => {
		try {
			if (!$userGrid || !Array.isArray($userGrid) || $userGrid.length === 0) return false;
			
			for (let row = 0; row < SUDOKU_SIZE; row++) {
				if (!$userGrid[row] || !Array.isArray($userGrid[row])) return false;
				for (let col = 0; col < SUDOKU_SIZE; col++) {
					if ($userGrid[row][col] === 0) return false;
				}
			}
			// No empty fields...

			return ($invalidCells && $invalidCells.length === 0);
		} catch (error) {
			console.error('Error calculating game won:', error);
			return false;
		}
	},
	false,
);